// entityRef is a parsed "<type>:<id>" reference (e.g. opportunity:88).
type entityRef struct {
	Type string `json:"type"`
	ID   int64  `json:"id"`
}

// parseEntityRef parses "opportunity:88" into {opportunity, 88}. It accepts an
// optional --id/--type override pair when the positional form is absent.
func parseEntityRef(s string) (entityRef, error) {
	parts := strings.SplitN(strings.TrimSpace(s), ":", 2)
	if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
		return entityRef{}, fmt.Errorf("expected <type>:<id> (e.g. opportunity:88), got %q", s)
	}
	id, err := strconv.ParseInt(strings.TrimSpace(parts[1]), 10, 64)
	if err != nil {
		return entityRef{}, fmt.Errorf("invalid id in %q: %w", s, err)
	}
	return entityRef{Type: strings.ToLower(strings.TrimSpace(parts[0])), ID: id}, nil
}

// whoResult is the assembled contact-graph view of one opportunity.
type whoResult struct {
	Opportunity map[string]any   `json:"opportunity"`
	Company     map[string]any   `json:"company,omitempty"`
	People      []map[string]any `json:"people"`
	Activities  []map[string]any `json:"activities"`
}

func newNovelWhoCmd(flags *rootFlags) *cobra.Command {
	var flagID int64
	var flagType string
	var flagDB string

	cmd := &cobra.Command{
		Use:         "who [entity:id]",
		Short:       "Joins an opportunity to its company, people, and recent activities into one related-records view.",
		Example:     "opportunity:88 --agent",
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 && cmd.Flags().NFlag() == 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				return nil
			}

			var ref entityRef
			var err error
			if len(args) > 0 {
				ref, err = parseEntityRef(args[0])
				if err != nil {
					_ = cmd.Usage()
					return usageErr(err)
				}
			} else if flagID != 0 && flagType != "" {
				ref = entityRef{Type: strings.ToLower(flagType), ID: flagID}
			} else {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("provide <entity:id> (e.g. opportunity:88) or --id and --type"))
			}
			if ref.Type != "opportunity" {
				_ = cmd.Usage()
				return usageErr(fmt.Errorf("who currently supports only opportunity:<id> (got type %q)", ref.Type))
			}

			dbPath := flagDB
			if dbPath == "" {
				dbPath = defaultDBPath("copper-pp-cli")
			}
			if _, err := os.Stat(dbPath); os.IsNotExist(err) {
				fmt.Fprintf(cmd.ErrOrStderr(), "no local mirror at %s\nrun: copper-pp-cli sync --resources opportunities --db %s\n", dbPath, dbPath)
				if flags.asJSON || flags.agent {
					fmt.Fprintln(cmd.OutOrStdout(), "{}")
				}
				return nil
			}

			db, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening local database: %w\nRun 'copper-pp-cli sync' first.", err)
			}
			defer db.Close()

			res, err := runWho(cmd.Context(), db.DB(), ref.ID)
			if err != nil {
				return err
			}
			if res == nil {
				return notFoundErr(fmt.Errorf("opportunity %d not found in local mirror", ref.ID))
			}
			return renderWho(cmd.OutOrStdout(), res, flags)
		},
	}
	cmd.Flags().Int64Var(&flagID, "id", 0, "Entity id (alternative to positional entity:id)")
	cmd.Flags().StringVar(&flagType, "type", "", "Entity type (e.g. opportunity)")
	cmd.Flags().StringVar(&flagDB, "db", "", "SQLite database file path (default: resolved data directory data.db)")
	return cmd
}

// jsonRowByID loads the data JSON column for one row of a typed table, keyed
// by the numeric id. Returns nil (not an error) when no row matches.
func jsonRowByID(ctx context.Context, db *sql.DB, table string, id int64) (map[string]any, error) {
	var raw string
	// id is stored as TEXT; compare via CAST so 88 matches "88".
	err := db.QueryRowContext(ctx,
		fmt.Sprintf(`SELECT data FROM %s WHERE CAST(id AS INTEGER) = ? LIMIT 1`, table), id).Scan(&raw)
	if err == sql.ErrNoRows {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("loading %s %d: %w", table, id, err)
	}
	var obj map[string]any
	if err := json.Unmarshal([]byte(raw), &obj); err != nil {
		return nil, fmt.Errorf("decoding %s %d: %w", table, id, err)
	}
	return obj, nil
}

// runWho assembles the related-records view for one opportunity from the local
// store: company, primary contact, and recent activities (parent==this opp).
func runWho(ctx context.Context, db *sql.DB, oppID int64) (*whoResult, error) {
	opp, err := jsonRowByID(ctx, db, "opportunities", oppID)
	if err != nil {
		return nil, err
	}
	if opp == nil {
		return nil, nil
	}

	res := &whoResult{Opportunity: opp, People: []map[string]any{}, Activities: []map[string]any{}}

	if cid, ok := asInt64(opp["company_id"]); ok && cid != 0 {
		company, err := jsonRowByID(ctx, db, "companies", cid)
		if err != nil {
			return nil, err
		}
		if company != nil {
			res.Company = company
		}
	}

	if pid, ok := asInt64(opp["primary_contact_id"]); ok && pid != 0 {
		person, err := jsonRowByID(ctx, db, "people", pid)
		if err != nil {
			return nil, err
		}
		if person != nil {
			res.People = append(res.People, person)
		}
	}

	acts, err := activitiesForParent(ctx, db, "opportunity", oppID, 10)
	if err != nil {
		return nil, err
	}
	res.Activities = acts
	return res, nil
}

// activitiesForParent returns up to limit activities whose parent matches the
// given type/id, newest first by activity_date.
func activitiesForParent(ctx context.Context, db *sql.DB, parentType string, parentID int64, limit int) ([]map[string]any, error) {
	rows, err := db.QueryContext(ctx, `
		SELECT data FROM activities
		WHERE CAST(json_extract(data,'$.parent.id') AS INTEGER) = ?
		  AND LOWER(COALESCE(json_extract(data,'$.parent.type'), '')) = ?
		ORDER BY COALESCE(activity_date, json_extract(data,'$.activity_date'), 0) DESC
		LIMIT ?`, parentID, strings.ToLower(parentType), limit)
	if err != nil {
		return nil, fmt.Errorf("loading activities: %w", err)
	}
	defer rows.Close()

	out := []map[string]any{}
	for rows.Next() {
		var raw string
		if err := rows.Scan(&raw); err != nil {
			return nil, err
		}
		var obj map[string]any
		if err := json.Unmarshal([]byte(raw), &obj); err != nil {
			continue
		}
		out = append(out, obj)
	}
	return out, rows.Err()
}

// asInt64 coerces a JSON-decoded value (float64, string, json.Number) to int64.
func asInt64(v any) (int64, bool) {
	switch n := v.(type) {
	case float64:
		return int64(n), true
	case int64:
		return n, true
	case int:
		return int64(n), true
	case json.Number:
		i, err := n.Int64()
		return i, err == nil
	case string:
		i, err := strconv.ParseInt(strings.TrimSpace(n), 10, 64)
		return i, err == nil
	}
	return 0, false
}

func renderWho(w io.Writer, res *whoResult, flags *rootFlags) error {
	if flags.asJSON || flags.agent {
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		return enc.Encode(res)
	}
	name, _ := res.Opportunity["name"].(string)
	fmt.Fprintf(w, "Opportunity: %v %s\n", res.Opportunity["id"], name)
	if res.Company != nil {
		fmt.Fprintf(w, "Company:     %v %v\n", res.Company["id"], res.Company["name"])
	} else {
		fmt.Fprintln(w, "Company:     (none)")
	}
	fmt.Fprintf(w, "People:      %d\n", len(res.People))
	for _, p := range res.People {
		fmt.Fprintf(w, "  - %v %v\n", p["id"], p["name"])
	}
	fmt.Fprintf(w, "Activities:  %d (most recent first)\n", len(res.Activities))
	for _, a := range res.Activities {
		fmt.Fprintf(w, "  - %v %v\n", a["id"], a["details"])
	}
	return nil
}
